mapper.select:
select b.breed_id, b.category_id, c.name as category_name, b.code, b.name, b.sort, b.enabled, b.is_default from breed b left join category c on b.category_id = c.category_id
and b.category_id = #{categoryId} and b.name like concat('%', #{name}, '%') and b.enabled = #{enabled}
order by b.category_id, b.sort, b.name

mapper.update:
update breed
category_id = #{categoryId}, code = #{code}, name = #{name}, sort = #{sort}, enabled = #{enabled}, is_default = #{defaultBreed},
where breed_id = #{breedId}
